    if (data.isActive === undefined) issues.push(`${doc.id}: missing isActive`);
    if (data.isSold === undefined) issues.push(`${doc.id}: missing isSold`);
    if (!data.createdAt) issues.push(`${doc.id}: missing createdAt`);
    
    if (issues.length === 0) valid++;
  });
  
