  if (!cleanPhone.startsWith('+359')) {
    return {
      valid: false,
      message: 'Phone must start with +359 / Телефонът трябва да започва с +359'
    };
  }

  if (cleanPhone.length !== 13) { // +359 + 9 digits
    return {
      valid: false,
      message: 'Invalid phone format / Невалиден формат на телефон'
    };
  }

  return { valid: true };
};

